return ['domain'=>NULL,'plural-forms'=>'nplurals=3; plural=n%10==1 && n%100!=11 ? 0 : n%10>=2 && n%10<=4 && (n%100<10 || n%100>=20) ? 1 : 2;','language'=>'uk','pot-creation-date'=>'2026-05-05 23:24+0200','po-revision-date'=>'2026-05-05 23:50+0200','translation-revision-date'=>'2026-05-05 23:50+0200','project-id-version'=>'Transliterator','x-generator'=>'Poedit 3.9','messages'=>['Block Editor: Script selector' . "\4" . 'Latin'=>'Латиниця','Block Editor: Script selector' . "\4" . 'Cyrillic'=>'Кирилиця','Block Editor: Script selector' . "\4" . 'Choose your display type:'=>'Виберіть тип відображення:','Block Editor: Script selector' . "\4" . 'Script Selector'=>'Перемикач писемності','Block Editor: Script selector' . "\4" . 'Inline'=>'Вбудований','Block Editor: Script selector' . "\4" . 'Select'=>'Вибір','Block Editor: Script selector' . "\4" . 'List'=>'Список','Block Editor: Script selector' . "\4" . 'List items'=>'Елементи списку','Block Editor: Script selector' . "\4" . 'Separator:'=>'Роздільник:','Block Editor: Script selector' . "\4" . 'Cyrillic caption:'=>'Підпис для кирилиці:','Block Editor: Script selector' . "\4" . 'Latin Caption:'=>'Підпис для латиниці:','undefined'=>'не визначено','Freelance Jobs - Find or post freelance jobs'=>'Фриланс-вакансії — знайдіть роботу або розмістіть вакансії для фрилансерів','Contra Team - A complete hosting solution in one place'=>'Contra Team — повне рішення для хостингу в одному місці','Transliteration'=>'Транслітерація','Latin'=>'Латиниця','Cyrillic'=>'Кирилиця','Help'=>'Довідка','To insert language script selector just add a relative link after the link\'s keyword, example :'=>'Щоб вставити перемикач писемності, просто додайте відносне посилання після ключового слова посилання, наприклад:','You can also use'=>'Ви також можете використовувати','for change to Latin or use'=>'для перемикання на латиницю або використовуйте','for change to Cyrillic'=>'для перемикання на кирилицю','Add to Menu'=>'Додати до меню','The name of this navigation is written by always putting the Latin name first, then the Cyrillic one second, separated by the sign %s'=>'Назва цього пункту навігації завжди записується так: спочатку латинська назва, потім кирилична, розділені знаком %s','Example: Latinica | Ћирилица'=>'Приклад: Латиниця | Кирилиця','Note that the white space around them will be cleared.'=>'Зверніть увагу, що пробіли навколо них буде видалено.','You have been using <b> %1$s </b> plugin for a while. We hope you liked it!'=>'Ви вже деякий час користуєтеся плагіном <b> %1$s </b>. Сподіваємося, він вам сподобався!','Please give us a quick rating, it works as a boost for us to keep working on the plugin!'=>'Будь ласка, швидко оцініть нас, це стане для нас чудовою підтримкою й допоможе й надалі працювати над плагіном!','Rate Now!'=>'Оцінити зараз!','I\'ve already done that!'=>'Я вже це зробив!','Hey there! It\'s been a while since you\'ve been using the <b> %1$s </b> plugin'=>'Привіт! Ви вже деякий час користуєтеся плагіном <b> %1$s </b>','I\'m glad to hear you\'re enjoying the plugin. I\'ve put a lot of time and effort into ensuring that your website runs smoothly. If you\'re feeling generous, how about %s for my hard work? 😊'=>'Радий чути, що вам подобається цей плагін. Я вклав багато часу й зусиль, щоб ваш сайт працював без збоїв. Якщо хочете віддячити мені, як щодо %s за мою працю? 😊','treating me to a coffee'=>'пригостити мене кавою','Or simply %s forever.'=>'Або просто %s назавжди.','hide this message'=>'сховати це повідомлення','Hey there! It\'s been a while since you\'ve been using the <b>%1$s</b> plugin'=>'Привіт! Ви вже деякий час користуєтеся плагіном <b>%1$s</b>','I\'m really happy to see this plugin being useful for your website. If you ever feel like giving back, here\'s one way to do it.'=>'Мені дуже приємно бачити, що цей плагін корисний для вашого сайту. Якщо ви захочете віддячити, ось один зі способів це зробити.','Bank account (Banca Intesa a.d. Beograd):'=>'Банківський рахунок (Banca Intesa a.d. Beograd):','Every little bit helps, and I truly appreciate it! ❤️'=>'Будь-яка допомога важлива, і я щиро це ціную! ❤️','Find Work or %1$s in Serbia, Bosnia, Croatia, and Beyond!'=>'Знайдіть роботу або %1$s у Сербії, Боснії, Хорватії та за їх межами!','Visit %2$s to connect with skilled professionals across the region. Whether you need a project completed or are looking for work, our platform is your gateway to successful collaboration.'=>'Відвідайте %2$s, щоб зв’язатися з кваліфікованими фахівцями по всьому регіону. Потрібен вам виконавець для проєкту чи ви шукаєте роботу, наша платформа стане вашим шляхом до успішної співпраці.','Hire Top Freelancers'=>'Найміть найкращих фрилансерів','Freelance Jobs'=>'Фриланс-вакансії','Join us today!'=>'Приєднуйтеся до нас уже сьогодні!','This plugin uses cookies and should be listed in your Privacy Policy page to prevent privacy issues.'=>'Цей плагін використовує cookie-файли й має бути зазначений на сторінці вашої політики конфіденційності, щоб уникнути проблем із приватністю.','Suggested text:'=>'Рекомендований текст:','This website uses the %1$s plugin to transliterate content.'=>'Цей сайт використовує плагін %1$s для транслітерації вмісту.','This is a simple and easy add-on with which this website translates content from Cyrillic to Latin and vice versa. This transliteration plugin also supports special shortcodes and functions that use cookies to specify the language script.'=>'Це простий і зручний додаток, за допомогою якого цей сайт переводить вміст із кирилиці на латиницю і навпаки. Цей плагін транслітерації також підтримує спеціальні шорткоди та функції, що використовують cookie для визначення писемності мови.','These cookies do not affect your privacy because they are not intended for tracking and analytics. These cookies can have only two values: "%1$s" or "%2$s".'=>'Ці cookie не впливають на вашу конфіденційність, оскільки не призначені для відстеження та аналітики. Ці cookie можуть мати лише два значення: \\"%1$s\\" або \\"%2$s\\".','Important upgrade notice for the version %s:'=>'Важливе повідомлення про оновлення для версії %s:','NOTE: Before doing the update, it would be a good idea to backup your WordPress installations and settings.'=>'ПРИМІТКА: Перед оновленням рекомендується зробити резервну копію ваших установок і налаштувань WordPress.','The %1$s cannot run on PHP versions older than PHP %2$s. Please contact your host and ask them to upgrade.'=>'%1$s не може працювати на версіях PHP старіших за PHP %2$s. Зв’яжіться з вашим хостинг-провайдером і попросіть оновити PHP.','Transliteration plugin requires attention:'=>'Плагін транслітерації потребує уваги:','Your plugin works under Only WooCoomerce mode and you need to %s because WooCommerce is no longer active.'=>'Ваш плагін працює в режимі Only WooCoomerce, і вам потрібно %s, оскільки WooCommerce більше не активний.','update your settings'=>'оновити налаштування','Transliteration plugin requires a Multibyte String PHP extension (mbstring).'=>'Плагіну транслітерації потрібне PHP-розширення Multibyte String (mbstring).','Without %s you will not be able to use this plugin.'=>'Без %s ви не зможете використовувати цей плагін.','Multibyte String Installation'=>'Встановлення Multibyte String','this PHP extension'=>'це PHP-розширення','The %1$s cannot run on WordPress versions older than %2$s. Please update your WordPress installation.'=>'%1$s не може працювати на версіях WordPress старіших за %2$s. Будь ласка, оновіть вашу установку WordPress.','Global Settings'=>'Глобальні налаштування','My site is'=>'Мій сайт','Transliteration Mode'=>'Режим транслітерації','First visit mode'=>'Режим першого відвідування','Language scheme'=>'Мовна схема','Plugin Mode'=>'Режим плагіна','Force transliteration permalinks to latin'=>'Примусово транслітерувати постійні посилання в латиницю','Filters'=>'Фільтри','Transliteration Filters'=>'Фільтри транслітерації','Exclude Latin words that you do not want to be transliterated to the Cyrillic.'=>'Виключіть латинські слова, які не потрібно транслітерувати в кирилицю.','Exclude Cyrillic words that you do not want to be transliterated to the Latin.'=>'Виключіть кириличні слова, які не потрібно транслітерувати в латиницю.','Special Settings'=>'Спеціальні налаштування','Enable cache support'=>'Увімкнути підтримку кешу','Force widget transliteration'=>'Примусова транслітерація віджетів','Force e-mail transliteration'=>'Примусова транслітерація електронної пошти','Force transliteration for WordPress REST API'=>'Примусова транслітерація для WordPress REST API','Force transliteration for AJAX calls'=>'Примусова транслітерація для AJAX-запитів','EXPERIMENTAL'=>'ЕКСПЕРИМЕНТАЛЬНО','JavaScript Dynamic Transliteration'=>'Динамічна транслітерація JavaScript','WP Admin'=>'WP Admin','WP-Admin transliteration'=>'Транслітерація WP-Admin','Allow Cyrillic Usernames'=>'Дозволити кириличні імена користувачів','Allow Admin Tools'=>'Дозволити інструменти адміністратора','Media Settings'=>'Налаштування медіа','Transliterate filenames to latin'=>'Транслітерувати імена файлів у латиницю','Filename delimiter'=>'Роздільник імені файлу','WordPress Search'=>'Пошук WordPress','Enable search transliteration'=>'Увімкнути транслітерацію пошуку','Fix Diacritics'=>'Виправити діакритичні знаки','Search Mode'=>'Режим пошуку','SEO Settings'=>'Налаштування SEO','Parameter URL selector'=>'Селектор параметра URL','RSS transliteration'=>'Транслітерація RSS','Exclusion'=>'Виключення','Language: %s'=>'Мова: %s','Misc.'=>'Різне','Enable body class'=>'Увімкнути клас body','Theme Support'=>'Підтримка теми','Support the Project'=>'Підтримайте проєкт','Contributors & Developers'=>'Учасники та розробники','This setting determines the mode of operation for the Transliteration plugin.'=>'Цей параметр визначає режим роботи плагіна транслітерації.','Carefully choose the option that is best for your site and the plugin will automatically set everything you need for optimal performance.'=>'Уважно виберіть варіант, який найкраще підходить вашому сайту, і плагін автоматично налаштує все необхідне для оптимальної роботи.','This section contains filters for exclusions, allowing you to specify content that should be excluded from transliteration, and also includes a filter to disable certain WordPress filters related to transliteration.'=>'Цей розділ містить фільтри винятків, що дають змогу вказати вміст, який слід виключити з транслітерації, а також фільтр для вимкнення деяких фільтрів WordPress, пов’язаних із транслітерацією.','These are special settings that can enhance transliteration and are used only if you need them.'=>'Це спеціальні налаштування, які можуть покращити транслітерацію та використовуються лише за потреби.','These settings apply to the administrative part.'=>'Ці налаштування застосовуються до адміністративної частини.','Upload, view and control media and files.'=>'Завантаження, перегляд і керування медіа та файлами.','Our plugin also has special SEO options that are very important for your project.'=>'Наш плагін також має спеціальні SEO-налаштування, які дуже важливі для вашого проєкту.','Within this configuration section, you have the opportunity to customize your experience by selecting the particular languages for which you wish to turn off the transliteration function. This feature is designed to give you greater control and adaptability over how the system handles transliteration, allowing you to disable it for specific languages based on your individual needs or preferences.'=>'У цьому розділі конфігурації ви можете налаштувати роботу системи, вибравши конкретні мови, для яких хочете вимкнути функцію транслітерації. Ця можливість дає вам більше контролю й гнучкості над тим, як система обробляє транслітерацію, дозволяючи вимикати її для окремих мов залежно від ваших потреб і вподобань.','Various interesting settings that can be used in the development of your project.'=>'Різні цікаві налаштування, які можна використовувати під час розробки вашого проєкту.','This setting determines the search mode within the WordPress core depending on the type of language located in the database.'=>'Цей параметр визначає режим пошуку в ядрі WordPress залежно від типу мови, що міститься в базі даних.','The search type setting is mostly experimental and you need to test each variant so you can get the best result you need.'=>'Налаштування типу пошуку переважно є експериментальним, і вам потрібно протестувати кожен варіант, щоб отримати найкращий результат.','Arabic'=>'Арабська','Armenian'=>'Вірменська','Define whether your primary alphabet on the site is Latin or Cyrillic. If the primary alphabet is Cyrillic then choose Cyrillic. If it is Latin, then choose Latin. This option is crucial for the plugin to work properly.'=>'Визначте, яка основна писемність використовується на вашому сайті: латиниця чи кирилиця. Якщо основний алфавіт — кирилиця, виберіть кирилицю. Якщо латиниця — виберіть латиницю. Цей параметр критично важливий для коректної роботи плагіна.','Define whether your primary alphabet on the site.'=>'Визначте, яка основна писемність використовується на сайті.','Transliteration disabled'=>'Транслітерацію вимкнено','Cyrillic to Latin'=>'Кирилиця в латиницю','Latin to Cyrillic'=>'Латиниця в кирилицю','Arabic to Latin'=>'Арабська в латиницю','Latin to Arabic'=>'Латиниця в арабську','Armenian to Latin'=>'Вірменська в латиницю','Latin to Armenian'=>'Латиниця у вірменську','This option determines the global transliteration of your web site. If you do not want to transliterate the entire website and use this plugin for other purposes, disable this option. This option does not affect to the functionality of short codes and tags.'=>'Цей параметр визначає глобальну транслітерацію вашого сайту. Якщо ви не хочете транслітерувати весь сайт і використовуєте цей плагін для інших цілей, вимкніть цю опцію. Ця опція не впливає на роботу шорткодів і тегів.','This option determines the type of language script that the visitors sees when they first time come to your site.'=>'Цей параметр визначає, яку писемність побачать відвідувачі під час першого відвідування вашого сайту.','Automatical'=>'Автоматично','This option defines the language script. Automatic script detection is the best way but if you are using a WordPress installation in a language that does not match the scripts supported by this plugin, then choose on which script you want the transliteration to be performed.'=>'Цей параметр визначає писемність мови. Автоматичне визначення писемності — найкращий варіант, але якщо ви використовуєте установку WordPress мовою, що не збігається з писемностями, підтримуваними цим плагіном, виберіть, для якої писемності має виконуватися транслітерація.','This option configures the operating mode of the entire plugin and affects all aspects of the site related to transliteration. Each mode has its own set of filters, which are activated based on your specific needs. It\'s important to take the time to review and customize these settings according to your preferences.'=>'Цей параметр налаштовує режим роботи всього плагіна й впливає на всі аспекти сайту, пов’язані з транслітерацією. Кожен режим має власний набір фільтрів, які активуються залежно від ваших потреб. Важливо приділити час перегляду й налаштуванню цих параметрів відповідно до ваших уподобань.','Forced transliteration can sometimes cause problems if Latin is translated into Cyrillic in pages and posts. To this combination must be approached experimentally.'=>'Примусова транслітерація інколи може спричиняти проблеми, якщо латиниця на сторінках і в записах переводиться в кирилицю. До цієї комбінації слід підходити експериментально.','Exclude filters you don\'t need (optional)'=>'Виключіть непотрібні фільтри (необов’язково)','Select the transliteration filters you want to exclude.'=>'Виберіть фільтри транслітерації, які хочете виключити.','The filters you select here will not be transliterated (these filters do not work on forced transliteration).'=>'Вибрані тут фільтри не будуть транслітеруватися (ці фільтри не працюють при примусовій транслітерації).','TIPS & TRICKS:'=>'ПОРАДИ ТА ХИТРОЩІ:','You can find details about some of the listed filters in this article:'=>'Деталі про деякі з перелічених фільтрів ви можете знайти в цій статті:','Since you are already a WooCommerce user, you also can see the following documentation: %s'=>'Оскільки ви вже використовуєте WooCommerce, ви також можете ознайомитися з такою документацією: %s','Separate words, phrases, names and expressions with the sign %s or put it in a new row. HTML is not allowed.'=>'Розділяйте слова, фрази, імена та вирази знаком %s або розміщуйте їх з нового рядка. HTML не дозволяється.','Yes'=>'Так','No'=>'Ні','JavaScript Dynamic Transliteration ensures that all dynamically loaded content is properly transliterated in real time. It processes AJAX, builder-generated, and frontend-rendered elements while preserving HTML structure, URLs, and excluded words. <b>This option is only needed if some content is not transliterated correctly.</b>'=>'Динамічна транслітерація JavaScript гарантує, що весь динамічно завантажуваний вміст буде коректно транслітеруватися в реальному часі. Вона обробляє AJAX, елементи, створені конструкторами, та елементи, відтворені на фронтенді, зберігаючи структуру HTML, URL і виключені слова. <b>Цей параметр потрібен лише тоді, коли частина вмісту транслітерується некоректно.</b>','If you have a problem caching your pages, our plugin solves this problem by clearing the cache when changing the language script.'=>'Якщо у вас виникають проблеми з кешуванням сторінок, наш плагін вирішує їх, очищаючи кеш під час зміни писемності мови.','This option forces the widget to transliterate. There may be some unusual behaviour in the rare cases.'=>'Цей параметр примусово вмикає транслітерацію віджета. У рідкісних випадках можлива незвична поведінка.','Enable this feature if you want to force transliteration of email content.'=>'Увімкніть цю функцію, якщо хочете примусово транслітерувати вміст електронної пошти.','Enable this feature if you want to force transliteration of WordPress REST API calls. The WordPress REST API is also used in many AJAX calls, WooCommerce, and page builders. It is recommended to be enabled by default.'=>'Увімкніть цю функцію, якщо хочете примусово транслітерувати виклики WordPress REST API. WordPress REST API також використовується в багатьох AJAX-запитах, WooCommerce і конструкторах сторінок. Рекомендується вмикати її за замовчуванням.','Enable this feature if you want to force transliteration of AJAX calls. If you want to avoid transliteration of specific individual AJAX calls, you must add a new POST or GET parameter to your AJAX call: %s'=>'Увімкніть цю функцію, якщо хочете примусово транслітерувати AJAX-запити. Якщо ви хочете уникнути транслітерації окремих AJAX-запитів, потрібно додати новий параметр POST або GET до вашого AJAX-запиту: %s','Enable if you want the WP-Admin area to be transliterated.'=>'Увімкніть, якщо хочете, щоб область WP-Admin транслітерувалася.','Allows to create users with usernames containing Cyrillic characters.'=>'Дозволяє створювати користувачів з іменами, що містять кириличні символи.','This feature enables you to easily transliterate titles and content directly within the WordPress editor. This functionality is available for various content types, including categories, pages, posts, and custom post types, ensuring a seamless experience when managing multilingual content on your site. With just a few clicks, you can switch between scripts, making your content accessible to a broader audience.'=>'Ця функція дає змогу легко транслітерувати заголовки та вміст безпосередньо в редакторі WordPress. Вона доступна для різних типів вмісту, зокрема категорій, сторінок, записів і користувацьких типів записів, забезпечуючи зручну роботу з багатомовним вмістом на вашому сайті. Усього кількома кліками ви можете перемикатися між писемностями, роблячи вміст доступним для ширшої аудиторії.','Enable if you want to force cyrillic permalinks to latin.'=>'Увімкніть, якщо хочете примусово перетворювати кириличні постійні посилання на латиницю.','Enable if you want to convert cyrillic filenames to latin.'=>'Увімкніть, якщо хочете перетворювати кириличні імена файлів на латиницю.','hyphen (default)'=>'дефіс (за замовчуванням)','underscore'=>'підкреслення','dot'=>'крапка','tilde'=>'тильда','vartical bar'=>'вертикальна риска','asterisk'=>'зірочка','Filename delimiter, example:'=>'Роздільник імені файлу, приклад:','my-upload-file.jpg'=>'my-upload-file.jpg','Approve if you want transliteration for the search field.'=>'Увімкніть, якщо хочете транслітерацію для поля пошуку.','Try to fix the diacritics in the search field.'=>'Спробувати виправляти діакритичні знаки в полі пошуку.','Automatical (recommended)'=>'Автоматично (рекомендовано)','Based on the plugin mode'=>'На основі режиму плагіна','The search has two working modes. Choose the one that works best with your search.'=>'Пошук має два режими роботи. Виберіть той, який найкраще підходить для вашого пошуку.','(safe)'=>'(безпечно)','(standard)'=>'(стандартно)','(optional)'=>'(необов’язково)','This option dictates which URL parameter will be used to change the language.'=>'Цей параметр визначає, який параметр URL використовуватиметься для зміни мови.','This option transliterate the RSS feed.'=>'Цей параметр транслітерує RSS-стрічку.','Transliterate'=>'Транслітерувати','Omit the transliteration'=>'Пропустити транслітерацію','This option adds CSS classes to your body HTML tag. These CSS classes vary depending on the language script.'=>'Цей параметр додає CSS-класи до вашого HTML-тега body. Ці CSS-класи залежать від писемності мови.','Enable Theme Support'=>'Увімкнути підтримку теми','Disable Theme Support'=>'Вимкнути підтримку теми','If you don\'t require transliteration support for your theme, you can disable it for your current theme here.'=>'Якщо вашій темі не потрібна підтримка транслітерації, ви можете вимкнути її для поточної теми тут.','This mode has no filters.'=>'У цьому режимі немає фільтрів.','Transliterator is free to use and actively maintained. Ongoing updates, performance improvements, and new features require continuous time and resources.'=>'Transliterator безкоштовний у використанні та активно підтримується. Постійні оновлення, покращення продуктивності й нові функції потребують часу та ресурсів.','If the plugin adds value to your work, you are welcome to support its further development with a voluntary contribution.'=>'Якщо плагін приносить користь вашій роботі, ви можете підтримати його подальший розвиток добровільним внеском.','Banca Intesa a.d. Beograd'=>'Banca Intesa a.d. Beograd','Thank you for your support.'=>'Дякуємо за вашу підтримку.','If you want to support our work and effort, if you have new ideas or want to improve the existing code, %s.'=>'Якщо ви хочете підтримати нашу роботу й зусилля, якщо у вас є нові ідеї або ви хочете покращити наявний код, %s.','join our team'=>'приєднуйтеся до нашої команди','Settings saved.'=>'Налаштування збережено.','Settings'=>'Налаштування','Shortcodes'=>'Шорткоди','PHP Functions'=>'PHP-функції','5 stars?'=>'5 зірок?','Transliteration Settings'=>'Налаштування транслітерації','To Latin'=>'У латиницю','To Cyrillic'=>'У кирилицю','Transliterate:'=>'Транслітерувати:','Loading...'=>'Завантаження...','Please wait! Do not close the window or leave the page until this operation is completed!'=>'Будь ласка, зачекайте! Не закривайте вікно та не залишайте сторінку, доки операцію не буде завершено!','DONE!!!'=>'ГОТОВО!!!','PLEASE UPDATE PLUGIN SETTINGS'=>'БУДЬ ЛАСКА, ОНОВІТЬ НАЛАШТУВАННЯ ПЛАГІНА','Carefully review the transliteration plugin settings and adjust how it fits your WordPress installation. It is important that every time you change the settings, you test the parts of the site that are affected by this plugin.'=>'Уважно перевірте налаштування плагіна транслітерації та налаштуйте їх відповідно до вашої установки WordPress. Важливо, щоб щоразу після зміни налаштувань ви перевіряли ті частини сайту, на які впливає цей плагін.','Tags'=>'Теги','Transliteration Tool'=>'Інструмент транслітерації','Permalink Tool'=>'Інструмент постійних посилань','General Settings'=>'Загальні налаштування','Documentation'=>'Документація','Tools'=>'Інструменти','Debug'=>'Налагодження','Credits'=>'Подяки','Save Changes'=>'Зберегти зміни','Available shortcodes'=>'Доступні шорткоди','Available PHP Functions'=>'Доступні PHP-функції','Available Tags'=>'Доступні теги','Converter for transliterating Cyrillic into Latin and vice versa'=>'Конвертер для транслітерації кирилиці в латиницю і навпаки','Permalink Transliteration Tool'=>'Інструмент транслітерації постійних посилань','Debug information'=>'Налагоджувальна інформація','WordPress Transliterator'=>'Транслітератор WordPress','Quick Access:'=>'Швидкий доступ:','Rate us'=>'Оцініть нас','Current Settings:'=>'Поточні налаштування:','Transliteration Mode:'=>'Режим транслітерації:','Cache Support:'=>'Підтримка кешу:','Media Transliteration:'=>'Транслітерація медіа:','Permalink Transliteration:'=>'Транслітерація постійних посилань:','Transliterator plugin options are not yet available. Please update plugin settings!'=>'Параметри плагіна Transliterator поки недоступні. Будь ласка, оновіть налаштування плагіна!','Support'=>'Підтримка','This plugin is 100% free. If you want to buy us one coffee, beer or in general help the development of this plugin through a monetary donation, you can do it in the following ways:'=>'Цей плагін на 100% безкоштовний. Якщо ви хочете пригостити нас кавою, пивом або загалом допомогти розвитку цього плагіна грошовою пожертвою, ви можете зробити це такими способами:','From Serbia'=>'Із Сербії','This is a light weight, simple and easy plugin with which you can transliterate your WordPress installation from Cyrillic to Latin and vice versa in a few clicks. This transliteration plugin also supports special shortcodes that you can use to partially transliterate parts of the content.'=>'Це легкий, простий і зручний плагін, за допомогою якого ви можете в кілька кліків транслітерувати вашу установку WordPress із кирилиці в латиницю і навпаки. Цей плагін транслітерації також підтримує спеціальні шорткоди, які можна використовувати для часткової транслітерації вмісту.','Sponsors of this plugin:'=>'Спонсори цього плагіна:','If you want to help develop this plugin and be one of the sponsors, please contact us at: %s'=>'Якщо ви хочете допомогти в розробці цього плагіна та стати одним зі спонсорів, зв’яжіться з нами за адресою: %s','Special thanks to the contributors in the development of this plugin:'=>'Особлива подяка учасникам розробки цього плагіна:','Copyright'=>'Авторські права','Copyright &copy; 2020 - %1$d %2$s by %3$s. All Right Reserved.'=>'Авторські права &copy; 2020 - %1$d %2$s, %3$s. Усі права захищено.','Transliterator – WordPress Transliteration'=>'Transliterator – транслітерація WordPress','This program is free software; you can redistribute it and/or modify it under the terms of the GNU General Public License as published by the Free Software Foundation; either version 2 of the License, or (at your option) any later version.'=>'Ця програма є вільним програмним забезпеченням; ви можете розповсюджувати її та/або змінювати на умовах GNU General Public License, опублікованої Free Software Foundation; або версії 2 ліцензії, або (на ваш вибір) будь-якої пізнішої версії.','This program is distributed in the hope that it will be useful, but WITHOUT ANY WARRANTY; without even the implied warranty of MERCHANTABILITY or FITNESS FOR A PARTICULAR PURPOSE.'=>'Ця програма розповсюджується з надією, що вона буде корисною, але БЕЗ ЖОДНИХ ГАРАНТІЙ; навіть без неявної гарантії КОМЕРЦІЙНОЇ ПРИДАТНОСТІ чи ПРИДАТНОСТІ ДЛЯ ПЕВНОЇ МЕТИ.','See the GNU General Public License for more details.'=>'Дивіться GNU General Public License для отримання докладнішої інформації.','You should have received a copy of the GNU General Public License along with this program; if not, write to the Free Software Foundation, Inc., 51 Franklin Street, Fifth Floor, Boston, MA 02110-1301, USA.'=>'Ви мали отримати копію GNU General Public License разом із цією програмою; якщо ні, напишіть до Free Software Foundation, Inc., 51 Franklin Street, Fifth Floor, Boston, MA 02110-1301, USA.','Plugin ID'=>'ID плагіна','Plugin version'=>'Версія плагіна','WordPress version'=>'Версія WordPress','Last plugin update'=>'Останнє оновлення плагіна','PHP version'=>'Версія PHP','PHP version ID'=>'ID версії PHP','PHP architecture'=>'Архітектура PHP','%d bit'=>'%d біт','WordPress debug'=>'Налагодження WordPress','On'=>'Увімкнено','Off'=>'Вимкнено','WordPress multisite'=>'WordPress multisite','WooCommerce active'=>'WooCommerce активний','WooCommerce version'=>'Версія WooCommerce','Site title'=>'Назва сайту','Tagline'=>'Короткий опис','WordPress address (URL)'=>'Адреса WordPress (URL)','Admin email'=>'Email адміністратора','Encoding for pages and feeds'=>'Кодування сторінок і стрічок','Content-Type'=>'Content-Type','Site Language'=>'Мова сайту','Server time'=>'Час сервера','WordPress directory path'=>'Шлях до каталогу WordPress','Operting system'=>'Операційна система','User agent'=>'User agent','Plugin directory path'=>'Шлях до каталогу плагіна','Plugin settings'=>'Налаштування плагіна','These are available PHP functions that you can use in your themes and plugins.'=>'Це доступні PHP-функції, які можна використовувати у ваших темах і плагінах.','Determines whether the site is already in Cyrillic.'=>'Визначає, чи сайт уже використовує кирилицю.','This function provides information on whether the currently active language is excluded from transliteration.'=>'Ця функція повідомляє, чи виключено поточну активну мову з транслітерації.','Transliteration of some text or content into the desired script.'=>'Транслітерація певного тексту або вмісту в потрібну писемність.','The <b><i>$type</i></b> parameter has two values: <code>cyr_to_lat</code> (Cyrillic to Latin) and <code>lat_to_cyr</code> (Latin to Cyrillic)'=>'Параметр <b><i>$type</i></b> має два значення: <code>cyr_to_lat</code> (кирилиця в латиницю) і <code>lat_to_cyr</code> (латиниця в кирилицю)','Transliteration from Cyrillic to Latin.'=>'Транслітерація з кирилиці в латиницю.','Transliteration from Latin to Cyrillic.'=>'Транслітерація з латиниці в кирилицю.','Transliterates Cyrillic characters to Latin, converting them to their basic ASCII equivalents by removing diacritics.'=>'Транслітерує кириличні символи в латиницю, перетворюючи їх на базові ASCII-відповідники шляхом видалення діакритики.','Get active script.'=>'Отримати активну писемність.','This function displays a selector for the transliteration script.'=>'Ця функція відображає перемикач писемності для транслітерації.','Parameters'=>'Параметри','This attribute contains an associative set of parameters for this function:'=>'Цей атрибут містить асоціативний набір параметрів для цієї функції:','(string) The type of selector that will be displayed on the site. It can be: %1$s, %2$s, %3$s, %4$s, %5$s or %6$s. Default: %1$s'=>'(string) Тип селектора, який відображатиметься на сайті. Він може бути: %1$s, %2$s, %3$s, %4$s, %5$s або %6$s. За замовчуванням: %1$s','(bool) determines whether it will be displayed through an echo or as a string. Default: %s'=>'(bool) визначає, чи буде значення виводитися через echo або як рядок. За замовчуванням: %s','(string) Separator to be used when the selector type is %s. Default: %s'=>'(string) Роздільник, який використовується, коли тип селектора — %s. За замовчуванням: %s','(string) Text for Cyrillic link. Default: %s'=>'(string) Текст для посилання на кирилицю. За замовчуванням: %s','(string) Text for Latin link. Default: %s'=>'(string) Текст для посилання на латиницю. За замовчуванням: %s','This tool enables you to convert all existing Cyrillic permalinks in your database to Latin characters.'=>'Цей інструмент дає змогу перетворити всі наявні кириличні постійні посилання у вашій базі даних на латинські символи.','Warning:'=>'Попередження:','This option is dangerous and can create unexpected problems. Once you run this script, all permalinks in your database will be modified and this can affect on the SEO causing a 404 error.'=>'Цей параметр небезпечний і може спричинити непередбачувані проблеми. Після запуску цього скрипта всі постійні посилання у вашій базі даних буде змінено, що може вплинути на SEO та спричинити помилку 404.','Before proceeding, consult with your SEO specialist, as you will likely need to resubmit your sitemap and adjust other settings to update the permalinks in search engines.'=>'Перш ніж продовжити, проконсультуйтеся зі спеціалістом із SEO, оскільки вам, імовірно, доведеться повторно подати sitemap і скоригувати інші налаштування, щоб оновити постійні посилання в пошукових системах.','For advanced users, this function can also be executed via WP-CLI using the command'=>'Для досвідчених користувачів цю функцію також можна виконати через WP-CLI за допомогою команди','Important: Make sure to %s before running this script.'=>'Важливо: обов’язково %s перед запуском цього скрипта.','back up your database'=>'зробіть резервну копію бази даних','This tool will affect on the following post types: %s'=>'Цей інструмент вплине на такі типи записів: %s','Let\'s do magic'=>'Зробімо магію','Are you sure you want this?'=>'Ви впевнені, що хочете цього?','Disclaimer'=>'Застереження','While this tool is designed to operate safely, there is always a small risk of unpredictable issues.'=>'Хоча цей інструмент розроблено для безпечної роботи, завжди існує невеликий ризик непередбачуваних проблем.','Note: We do not guarantee that this tool will function correctly on your server. By using it, you assume all risks and responsibilities for any potential issues.'=>'Примітка: ми не гарантуємо, що цей інструмент працюватиме коректно на вашому сервері. Використовуючи його, ви берете на себе всі ризики та відповідальність за можливі проблеми.','Backup your database before using this tool.'=>'Зробіть резервну копію бази даних перед використанням цього інструмента.','These are available shortcodes that you can use in your content, visual editors, themes and plugins.'=>'Це доступні шорткоди, які можна використовувати у вмісті, візуальних редакторах, темах і плагінах.','Skip transliteration'=>'Пропустити транслітерацію','Keep this original'=>'Залишити це без змін','(optional) correct HTML code.'=>'(необов’язково) коректний HTML-код.','Optional shortcode parameters'=>'Необов’язкові параметри шорткоду','(optional) correct diacritics.'=>'(необов’язково) виправити діакритичні знаки.','Add an image depending on the language script'=>'Додати зображення залежно від писемності мови','With this shortcode you can manipulate images and display images in Latin or Cyrillic depending on the setup.'=>'За допомогою цього шорткоду ви можете керувати зображеннями та відображати їх латиницею або кирилицею залежно від налаштувань.','Example'=>'Приклад','Main shortcode parameters'=>'Основні параметри шорткоду','URL (src) as shown in the Latin language'=>'URL (src), що відображається латиницею','URL (src) as shown in the Cyrillic language'=>'URL (src), що відображається кирилицею','(optional) URL (src) to the default image if Latin and Cyrillic are unavailable'=>'(необов’язково) URL (src) зображення за замовчуванням, якщо латиниця й кирилиця недоступні','(optional) title (alt) description of the image for Cyrillic'=>'(необов’язково) опис title (alt) зображення для кирилиці','(optional) caption description of the image for Cyrillic'=>'(необов’язково) опис підпису зображення для кирилиці','(optional) title (alt) description of the image for Latin'=>'(необов’язково) опис title (alt) зображення для латиниці','(optional) caption description of the image for Latin'=>'(необов’язково) опис підпису зображення для латиниці','(optional) title (alt) description of the image if Latin and Cyrillic are unavailable'=>'(необов’язково) опис title (alt) зображення, якщо латиниця й кирилиця недоступні','(optional) caption description of the imag if Latin and Cyrillic are unavailable'=>'(необов’язково) опис підпису зображення, якщо латиниця й кирилиця недоступні','Shortcode return'=>'Повернення шорткоду','HTML image corresponding to the parameters set in this shortcode.'=>'HTML-зображення, що відповідає параметрам, заданим у цьому шорткоді.','Language script menu'=>'Меню писемності мови','This shortcode displays a selector for the transliteration script.'=>'Цей шорткод відображає перемикач писемності для транслітерації.','(string) The type of selector that will be displayed on the site. It can be: "%1$s", "%2$s", "%3$s" or "%4$s"'=>'(string) Тип селектора, який відображатиметься на сайті. Він може бути: \\"%1$s\\", \\"%2$s\\", \\"%3$s\\" або \\"%4$s\\"','(string) Text for Cyrillic link. Default: Cyrillic'=>'(string) Текст для посилання на кирилицю. За замовчуванням: Кирилиця','(string) Text for Latin link. Default: Latin'=>'(string) Текст для посилання на латиницю. За замовчуванням: Латиниця','This shortcodes work independently of the plugin settings and can be used anywhere within WordPress pages, posts, taxonomies and widgets (if they support it).'=>'Ці шорткоди працюють незалежно від налаштувань плагіна й можуть використовуватися будь-де на сторінках, у записах, таксономіях і віджетах WordPress (якщо вони це підтримують).','These tags have a special purpose and work separately from short codes and can be used in fields where short codes cannot be used.'=>'Ці теги мають спеціальне призначення, працюють окремо від шорткодів і можуть використовуватися в полях, де шорткоди застосовувати не можна.','These tags have no additional settings and can be applied in plugins, themes, widgets and within other short codes.'=>'Ці теги не мають додаткових налаштувань і можуть застосовуватися в плагінах, темах, віджетах та всередині інших шорткодів.','Copy the desired text into one field and press the desired key to convert the text.'=>'Скопіюйте потрібний текст в одне поле й натисніть потрібну кнопку, щоб перетворити текст.','Convert to Latin'=>'Перетворити в латиницю','Convert to Cyrillic'=>'Перетворити в кирилицю','Reset'=>'Скинути','The %1$s shortcode has been deprecated as of version %2$s. Please update your content and use the new %3$s shortcode.'=>'Шорткод %1$s застарів, починаючи з версії %2$s. Будь ласка, оновіть вміст і використовуйте новий шорткод %3$s.','Transliteration shortcode does not have adequate parameters and translation is not possible. Please check the documentation.'=>'Шорткод транслітерації не має достатніх параметрів, і переклад неможливий. Будь ласка, перевірте документацію.','An error occurred while converting. Please refresh the page and try again.'=>'Під час перетворення сталася помилка. Будь ласка, оновіть сторінку й спробуйте знову.','The field is empty.'=>'Поле порожнє.','There was a communication problem. Please refresh the page and try again. If this does not solve the problem, contact the author of the plugin.'=>'Виникла проблема зі зв’язком. Будь ласка, оновіть сторінку й спробуйте знову. Якщо це не вирішить проблему, зв’яжіться з автором плагіна.','Phantom Mode (ultra fast DOM-based transliteration)'=>'Phantom Mode (надшвидка транслітерація на основі DOM)','Light mode (basic parts of the site)'=>'Легкий режим (базові частини сайту)','Standard mode (content, themes, plugins, translations, menu)'=>'Стандартний режим (вміст, теми, плагіни, переклади, меню)','Advanced mode (content, widgets, themes, plugins, translations, menu, permalinks, media)'=>'Розширений режим (вміст, віджети, теми, плагіни, переклади, меню, постійні посилання, медіа)','Forced transliteration (everything)'=>'Примусова транслітерація (усе)','Only WooCommerce (It bypasses all other transliterations and focuses only on WooCommerce)'=>'Лише WooCommerce (обходить усі інші види транслітерації та зосереджується лише на WooCommerce)','Dev Mode (Only for developers and testers)'=>'Режим розробника (лише для розробників і тестувальників)',' degrees '=>' градусів ',' divided by '=>' поділити на ',' times '=>' помножити на ',' plus-minus '=>' плюс-мінус ',' square root '=>' квадратний корінь ',' infinity '=>' нескінченність ',' almost equal to '=>' майже дорівнює ',' not equal to '=>' не дорівнює ',' identical to '=>' тотожно ',' less than or equal to '=>' менше або дорівнює ',' greater than or equal to '=>' більше або дорівнює ',' left '=>' ліворуч ',' right '=>' праворуч ',' up '=>' вгору ',' down '=>' вниз ',' left and right '=>' ліворуч і праворуч ',' up and down '=>' вгору і вниз ',' care of '=>' на ім’я ',' estimated '=>' приблизно ',' ohm '=>' ом ',' female '=>' жіночий ',' male '=>' чоловічий ',' Copyright '=>' Авторські права ',' Registered '=>' Зареєстровано ',' Trademark '=>' Торгова марка ','Option name'=>'Назва параметра','Value'=>'Значення','Key'=>'Ключ','Automatic'=>'Автоматично','Disabled'=>'Вимкнено','Please wait! Do not close the terminal or terminate the script until this operation is completed!'=>'Будь ласка, зачекайте! Не закривайте термінал і не переривайте скрипт, доки операцію не буде завершено!','Progress:'=>'Прогрес:','Updated page ID %1$d, (%2$s) at URL: %3$s'=>'Оновлено сторінку з ID %1$d, (%2$s) за URL: %3$s','%d permalink was successfully transliterated.'=>'%d постійне посилання успішно транслітеровано.' . "\0" . '%d постійні посилання успішно транслітеровано.' . "\0" . '%d постійних посилань успішно транслітеровано.','No changes to the permalink have been made.'=>'Змін до постійного посилання не внесено.','Choose one of the display types: "%1$s", "%2$s", "%3$s", "%4$s", "%5$s" or "%6$s"'=>'Виберіть один із типів відображення: \\"%1$s\\", \\"%2$s\\", \\"%3$s\\", \\"%4$s\\", \\"%5$s\\" або \\"%6$s\\"','Transliterator'=>'Transliterator','You do not have sufficient permissions to access this page.'=>'У вас недостатньо прав для доступу до цієї сторінки.','Security check failed. Please try again.'=>'Перевірка безпеки не пройшла. Будь ласка, спробуйте ще раз.','Transliterator - Network Settings'=>'Transliterator — мережеві налаштування','Select sites where the plugin should run when it is network-activated.'=>'Виберіть сайти, на яких має працювати плагін, коли його активовано в мережі.','Enable'=>'Увімкнути','Site'=>'Сайт','Domain'=>'Домен','Path'=>'Шлях','Site #%d'=>'Сайт №%d','Enable Transliterator on site ID %d'=>'Увімкнути Transliterator на сайті з ID %d','No sites found.'=>'Сайти не знайдено.','Save changes'=>'Зберегти зміни','Transliterator – Multilingual and Multi-script Text Conversion'=>'Transliterator — багатомовне та багатоскриптове перетворення тексту','https://wordpress.org/plugins/serbian-transliteration/'=>'https://wordpress.org/plugins/serbian-transliteration/','All-in-one Cyrillic to Latin transliteration plugin for WordPress. Supports Slavic, Arabic, Greek, and Central Asian scripts.'=>'Універсальний плагін транслітерації з кирилиці в латиницю для WordPress. Підтримує слов’янські, арабські, грецькі та центральноазійські писемності.','Ivijan-Stefan Stipić'=>'Ivijan-Stefan Stipić','https://profiles.wordpress.org/ivijanstefan/'=>'https://profiles.wordpress.org/ivijanstefan/']];
